package consumer

import (
	"encoding/json"
	"fmt"
	"log"
	"os"

	amqp "github.com/rabbitmq/amqp091-go"

	"notification-service/internal/handlers"
)

const (
	exchangeName = "notifications"
	queueName    = "notification-service.email"
	routingKey   = "email.*"
	prefetchCount = 10
)

type emailMessage struct {
	EventType string          `json:"event_type"`
	Timestamp string          `json:"timestamp"`
	Payload   json.RawMessage `json:"payload"`
}

func Start() error {
	conn, err := connect()
	if err != nil {
		return err
	}

	conn.NotifyClose(make(chan *amqp.Error, 1))

	ch, err := conn.Channel()
	if err != nil {
		return fmt.Errorf("open channel: %w", err)
	}

	if err := ch.Qos(prefetchCount, 0, false); err != nil {
		return fmt.Errorf("set prefetch: %w", err)
	}

	if err := ch.ExchangeDeclare(exchangeName, "topic", true, false, false, false, nil); err != nil {
		return fmt.Errorf("declare exchange: %w", err)
	}

	if _, err := ch.QueueDeclare(queueName, true, false, false, false, nil); err != nil {
		return fmt.Errorf("declare queue: %w", err)
	}

	if err := ch.QueueBind(queueName, routingKey, exchangeName, false, nil); err != nil {
		return fmt.Errorf("bind queue: %w", err)
	}

	msgs, err := ch.Consume(queueName, "", false, false, false, false, nil)
	if err != nil {
		return fmt.Errorf("start consume: %w", err)
	}

	log.Printf("[consumer] Listening on queue %q (routing: %s)", queueName, routingKey)

	connErrors := make(chan *amqp.Error, 1)
	conn.NotifyClose(connErrors)

	go func() {
		for msg := range msgs {
			processMessage(ch, msg)
		}
	}()

	if err := <-connErrors; err != nil {
		log.Printf("[consumer] Connection closed: %v", err)
		os.Exit(1)
	}

	return nil
}

func connect() (*amqp.Connection, error) {
	host := getenv("RABBITMQ_HOST", "rabbitmq")
	port := getenv("RABBITMQ_PORT", "5672")
	user := getenv("RABBITMQ_USER", "guest")
	pass := getenv("RABBITMQ_PASSWORD", "guest")
	vhost := getenv("RABBITMQ_VHOST", "/")

	url := fmt.Sprintf("amqp://%s:%s@%s:%s/%s", user, pass, host, port, vhost)
	log.Printf("[consumer] Connecting to RabbitMQ at %s:%s...", host, port)
	return amqp.Dial(url)
}

func processMessage(ch *amqp.Channel, msg amqp.Delivery) {
	var m emailMessage
	if err := json.Unmarshal(msg.Body, &m); err != nil {
		log.Printf("[consumer] Failed to parse message: %v", err)
		_ = msg.Nack(false, false)
		return
	}

	log.Printf("[consumer] Received %s", m.EventType)

	if err := dispatch(m); err != nil {
		log.Printf("[consumer] Failed to process %s: %v", m.EventType, err)
		_ = msg.Nack(false, false)
		return
	}

	_ = msg.Ack(false)
}

func dispatch(m emailMessage) error {
	switch m.EventType {
	case "email.password_reset":
		var payload handlers.PasswordResetPayload
		if err := json.Unmarshal(m.Payload, &payload); err != nil {
			return fmt.Errorf("unmarshal payload: %w", err)
		}
		return handlers.HandlePasswordReset(payload)
	default:
		log.Printf("[consumer] Unhandled event_type: %s", m.EventType)
		return nil
	}
}

func getenv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

package handlers

import (
	"fmt"

	"notification-service/internal/mailer"
)

type PasswordResetPayload struct {
	To      string `json:"to"`
	Subject string `json:"subject"`
	Data    struct {
		ResetURL  string `json:"reset_url"`
		ExpiresIn string `json:"expires_in"`
	} `json:"data"`
}

func HandlePasswordReset(payload PasswordResetPayload) error {
	html := fmt.Sprintf(`<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <style>
      body { font-family: Arial, sans-serif; background: #f9f9f9; margin: 0; padding: 0; }
      .container { max-width: 520px; margin: 40px auto; background: #fff; border-radius: 8px; padding: 40px; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
      h1 { font-size: 22px; color: #1a1a1a; margin-bottom: 8px; }
      p { color: #555; line-height: 1.6; }
      .btn { display: inline-block; margin: 24px 0; padding: 12px 28px; background: #2563eb; color: #fff; text-decoration: none; border-radius: 6px; font-weight: bold; }
      .footer { margin-top: 32px; font-size: 12px; color: #999; }
    </style>
  </head>
  <body>
    <div class="container">
      <h1>Reset Your Password</h1>
      <p>We received a request to reset your password. Click the button below to set a new one.</p>
      <a class="btn" href="%s">Reset Password</a>
      <p>This link expires in <strong>%s</strong>. If you did not request a password reset, you can safely ignore this email.</p>
      <div class="footer">
        ThatCookiesMine &mdash; Healthcare Appointment Platform
      </div>
    </div>
  </body>
</html>`, payload.Data.ResetURL, payload.Data.ExpiresIn)

	return mailer.SendMail(payload.To, payload.Subject, html)
}

package mailer

import (
	"fmt"
	"log"
	"net/smtp"
	"os"
	"strings"
)

const defaultFrom = "ThatCookiesMine <noreply@thatcookiesmine.dev>"
const defaultFromAddr = "noreply@thatcookiesmine.dev"

// sanitizeHeader removes CRLF characters to prevent SMTP header injection attacks.
// An attacker controlling `to` or `subject` could inject additional headers or
// recipients by embedding \r\n sequences.
func sanitizeHeader(value string) string {
	value = strings.ReplaceAll(value, "\r", "")
	value = strings.ReplaceAll(value, "\n", "")
	return value
}

func SendMail(to, subject, html string) error {
	host := getenv("SMTP_HOST", "mailhog")
	port := getenv("SMTP_PORT", "1025")

	to = sanitizeHeader(to)
	subject = sanitizeHeader(subject)

	msg := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=utf-8\r\n\r\n%s",
		defaultFrom, to, subject, html,
	)

	if err := smtp.SendMail(host+":"+port, nil, defaultFromAddr, []string{to}, []byte(msg)); err != nil {
		return err
	}

	log.Printf("[mailer] Sent email to %s", to)
	return nil
}

func getenv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

